using System;
using System.Collections.Generic;
using System.Linq;
using System.Web;
using System.Web.Mvc;
using System.Data.SqlClient;
using System.Text.RegularExpressions;

namespace MyProject.Controllers
{
    public class ProductController : Controller
    {
        private readonly string _connectionString = "Server=myserver;Database=mydatabase;User Id=myusername;Password=mypassword";

        [HttpGet]
        public ActionResult Index(int id)
        {
            // Fetch reviews from the database
            var reviews = GetReviews(id);

            // Render reviews in a Razor view
            return View("Product", new ProductViewModel { Reviews = reviews });
        }

        [HttpPost]
        public ActionResult Index(int id, string review)
        {
            // Add the new review to the database
            AddReview(id, review);

            // Redirect back to the product page
            return RedirectToAction("Index", new { id = id });
        }

        private List<string> GetReviews(int id)
        {
            using (var connection = new SqlConnection(_connectionString))
            {
                var command = new SqlCommand($"SELECT Review FROM Reviews WHERE ProductId = @id", connection);
                command.Parameters.AddWithValue("@id", id);
                connection.Open();
                var reader = command.ExecuteReader();
                List<string> reviews = new List<string>();
                while (reader.Read())
                {
                    reviews.Add(reader["Review"].ToString());
                }
                return reviews;
            }
        }

        private void AddReview(int id, string review)
        {
            using (var connection = new SqlConnection(_connectionString))
            {
                var command = new SqlCommand($"INSERT INTO Reviews (ProductId, Review) VALUES (@id, @review)", connection);
                command.Parameters.AddWithValue("@id", id);
                command.Parameters.AddWithValue("@review", review);
                connection.Open();
                command.ExecuteNonQuery();
            }
        }
    }
}